<?php declare(strict_types=1);require __DIR__.'/../includes/functions.php';
class Student{public function __construct(private string $name,private int $age){}public function display():string{return "Họ tên: {$this->name} — Tuổi: {$this->age}";}public function __destruct(){}}
$info='';$destroy='';$error='';if($_SERVER['REQUEST_METHOD']==='POST'){$name=trim((string)($_POST['name']??''));$age=filter_input(INPUT_POST,'age',FILTER_VALIDATE_INT);if($name===''||$age===false||$age<1||$age>120)$error='Tên không được trống và tuổi phải từ 1 đến 120.';else{$s=new Student($name,$age);$info=$s->display();unset($s);$destroy='Đối tượng Student đã được hủy sau khi xử lý.';}}
$pageTitle='Bài 02 - Student';$basePath='..';$current='bai02';require __DIR__.'/../includes/header.php';?>
<div class="crumb"><a href="../index.php">Trang chủ</a> / Bài 02</div><h1>Constructor và Destructor</h1><p class="subtitle">Khởi tạo Student, hiển thị dữ liệu và giải phóng đối tượng.</p><div class="two"><section class="card"><h2>Tạo sinh viên</h2><?php if($error):?><div class="alert err"><?=e($error)?></div><?php endif;?><form method="post"><div class="form-grid"><div class="group"><label>Họ tên</label><input name="name" value="<?=old('name','Nguyễn Văn A')?>" required></div><div class="group"><label>Tuổi</label><input type="number" name="age" min="1" max="120" value="<?=old('age','20')?>" required></div></div><div class="actions"><button class="btn primary">Khởi tạo Student</button></div></form></section><aside class="card"><div class="result"><h2>Kết quả</h2><?php if($info):?><div class="item"><strong><?=e($info)?></strong><div class="muted"><?=e($destroy)?></div></div><?php else:?><p class="muted">Chưa có đối tượng Student.</p><?php endif;?></div></aside></div><?php require __DIR__.'/../includes/footer.php';?>
